import 'package:flutter/material.dart';
import 'package:flutter_riverpod/flutter_riverpod.dart';
import '../../../core/state/app_state_notifier.dart';
import '../../../shared/widgets/app_shell.dart';

class CompaniesPage extends ConsumerWidget { const CompaniesPage({super.key}); @override Widget build(BuildContext context, WidgetRef ref) { final c = TextEditingController(); final s = ref.watch(appStateProvider); final title = 'companies'; final list = title == 'companies' ? s.companies.map((e)=>e.name).toList() : title == 'projects' ? s.projects.map((e)=>e.name).toList() : s.customers.map((e)=>e.name).toList(); return AppShell(title: title, child: ListView(padding: const EdgeInsets.all(16), children: [TextField(controller: c, decoration: const InputDecoration(labelText: 'Name')), const SizedBox(height: 12), FilledButton(onPressed: () { if (title == 'companies') ref.read(appStateProvider.notifier).addCompany(c.text); if (title == 'projects') ref.read(appStateProvider.notifier).addProject(name: c.text); if (title == 'customers') ref.read(appStateProvider.notifier).addCustomer(c.text); }, child: const Text('Add')), const SizedBox(height: 20), ...list.map((e)=>Card(child: ListTile(title: Text(e)))) ])); } }
